mapper.select:
SELECT COALESCE(SUM(ql.earned_xp), 0)
FROM quest_logs ql
JOIN quests q ON ql.quest_id = q.quest_id
WHERE ql.user_id  = #{userId}
  AND q.stat_type = #{statType}
  AND DATE(ql.completed_at) = CURDATE()


SELECT IF(
    EXISTS (SELECT 1 FROM quests WHERE user_id = #{userId} AND stat_type = #{statType} AND is_active = 1),
    DATEDIFF(CURDATE(), COALESCE(MAX(DATE(ql.completed_at)), '2000-01-01')),
    0
)
FROM quest_logs ql
JOIN quests q ON ql.quest_id = q.quest_id
WHERE ql.user_id  = #{userId}
  AND q.stat_type = #{statType}
